import{ApiRoutes}from"./routes";async function fetchJson(e,t){const o=await fetch(e,{credentials:"include",headers:{"Content-Type":"application/json",...t?.headers??{}},...t});if(!o.ok){const e=await o.text();throw new Error(`${o.status} ${o.statusText}: ${e}`)}return o.json()}export const IntakeApi={getState:e=>fetchJson(ApiRoutes.intake.state(e)),putState:(e,t)=>fetchJson(ApiRoutes.intake.state(e),{method:"PUT",body:JSON.stringify(t)}),addToCart:(e,t)=>fetchJson(ApiRoutes.intake.cartItems(e),{method:"POST",body:JSON.stringify({scope:t})}),removeCartItem:(e,t)=>fetchJson(ApiRoutes.intake.cartItem(e,t),{method:"DELETE"}),setAddons:(e,t)=>fetchJson(ApiRoutes.intake.addons(e),{method:"PUT",body:JSON.stringify({addons:t})}),evaluate:e=>fetchJson(ApiRoutes.intake.evaluate,{method:"POST",body:JSON.stringify({state:e})}),spec:e=>fetchJson(ApiRoutes.intake.spec,{method:"POST",body:JSON.stringify({state:e})}),checkout:e=>fetchJson(ApiRoutes.intake.checkout,{method:"POST",body:JSON.stringify({sessionKey:e})})};export const MarketplaceApi={hireDirect:()=>fetchJson(ApiRoutes.marketplace.hireDirect),portfolios:()=>fetchJson(ApiRoutes.marketplace.portfolios),freelancerPortfolio:e=>fetchJson(ApiRoutes.freelancer.portfolio(e)),fundedJobs:()=>fetchJson(ApiRoutes.marketplace.freelancerJobs),clientDashboard:()=>fetchJson(ApiRoutes.marketplace.clientDashboard),freelancerDashboard:()=>fetchJson(ApiRoutes.marketplace.freelancerDashboard),freelancerWorkspace:()=>fetchJson(ApiRoutes.freelancer.workspace),activateFreelancerWorkspace:()=>fetchJson(ApiRoutes.freelancer.workspaceActivate,{method:"POST"}),saveFreelancerWorkspace:e=>fetchJson(ApiRoutes.freelancer.workspace,{method:"PUT",body:JSON.stringify(e)}),adminStats:()=>fetchJson(ApiRoutes.marketplace.adminStats)};